-- --- Modèles d'AURA (2e modèle : DE2/D2) ---
-- Un buff appliqué affiche souvent un texte différent de son lancement (lui,
-- déjà traduit dans DB_Sorts). On AJOUTE ce 2e modèle à l'entrée EXISTANTE
-- (sans l'écraser) ; Sorts.lua essaie le modèle principal puis celui-ci — donc
-- les DEUX vues (lancement ET buff) sont traduites.
local function aura(id, de2, d2)
    if DB[id] then DB[id].DE2 = de2; DB[id].D2 = d2 end
end

