DB[301309]={D="Lancer Jugement augmente désormais votre Armure de 15 % pendant 15 s.",DE="Casting Reckoning now increases your Armor by 15% for 15 sec.",N="Résistance sacrée"}
aura(301310, "Level 20 Passive\nIncreases your spell power by 30% of your Agility and your critical strike rating by 15% of your Intellect.", "Passif niveau 20\nAugmente votre puissance de sort de 30% de votre Agilité et votre taux de coup critique de 15% de votre Intelligence.")
DB[301311]={D="Augmente la contribution d'armure de vos objets en mailles de 50 % et réduit les dégâts subis par les attaques à zone d'effet de 10 %.",DE="Increases your Armor contribution from mail items by 50% and reduces damage taken from area of effect attacks by 10%.",N="Rembourrage béni"}
