DB[520878]={D="Augmente votre régénération Focalisation de 30%.",DE="Increases your Focus regeneration by 30%.",N="Ruse"}
DB[520879]={D="Augmente vos chances de coup critique de 4 % et votre régénération Focalisation de 30 %.",DE="Increases your critical strike chance by 4% and Focus regeneration by 30%.",N="Banditisme"}
