DB[560182]={D="Dégâts infligés par Geode Barrage et Geodes pour augmenter les chances que l'ennemi soit touché de manière critique par des sorts de 3 % pendant 12 s.",DE="Damage dealt by Geode Barrage and Geodes to increase the chance for the enemy to be critically hit with spells by 3% for 12 sec.",N="Martèlement de terre"}
