DB[560195]={D="Augmente les soins du Croc du Serpent de 50 % et le Croc du Serpent ne peut plus manquer.",DE="Increases the healing of Serpent's Fang by 50% and Serpent's Fang can no longer miss.",N="Lieur de crocs"}
DB[560200]={D="Les soins périodiques efficaces avec le baume de Shadra ont désormais 10 % de chances de rendre votre prochain Alkahest en moins de 8 secondes gratuit et instantané.",DE="Effective periodic healing with Shadra's Balm now has a 10% chance to make your next Alkahest within 8 sec is free and instant.",N="Cycle de renaissance"}
DB[560205]={D="Lancer Berserker Rush vous confère désormais Né dans le sang.\nNé dans le sang\nLe combat alimente votre vitalité, en restaurant 15 points de vie et 9 Énergie en 3 s.",DE="Casting Berserker Rush now grants you Born in Blood.\nBorn in Blood\nBattle fuels your vitality, restoring 15 health and 9 Energy over 3 sec.",N="Vengeance pour Zul'jin"}
DB[560207]={D="Votre Smite Evil a désormais 25 % de chances de frapper à nouveau.\nTant que Flammes du péché est actif, les chances de déclencher cet effet sont augmentées de 10 %.",DE="Your Smite Evil now has a 25% chance to strike again.\nWhile you have Flames of Sin active, the chance to trigger this effect is increased by 10%.",N="Flammes des pécheurs"}
DB[560208]={D="Profanation restaure désormais 10+ShaP*.2+AP*.1 de vie plus 1% de vie maximale supplémentaire pour chaque cible touchée affectée par Ombre Brand.",DE="Desecrate now restores 10+ShaP*.2+AP*.1 health plus an additional 1% maximum health for each target struck affected by Shadow Brand.",N="Sombre mastodonte"}
