DB[561342]={D="Réduit le temps de recharge de Deathstalker, Soulstone Lure et Soul Shear de 25 %.",DE="Reduces the cooldown of Deathstalker, Soulstone Lure, and Soul Shear by 25%.",N="Dans le royaume des ombres"}
DB[561343]={D="Augmente vos chances d'esquive et de parade de 8%.",DE="Increases your dodge and parry chance by 8%.",N="Disciple du Néant"}
