DB[570120]={D="Augmente vos Force et Intelligence de 10%.",DE="Increases your Strength and Intellect by 10%.",N="Puissance solaire"}
DB[570128]={D="Court à haute vitesse vers un membre du groupe et intercepte la prochaine attaque en mêlee ou à distance contre lui, en plus de réduire son total de menace de $59667s1%.",DE="Your Invigoration now stacks 5 additional times.",N="Fluidité"}
DB[570136]={D="Augmente les dégâts de Crypt Plague de 50 % et Crypt Swarm inflige désormais 4 % de dégâts supplémentaires pour chaque maladie Nécromancien que vous avez sur la cible.",DE="Increases the damage of Crypt Plague by 50% and Crypt Swarm now deals 4% more damage for each Necromancer disease you have on the target.",N="Cryptes en éveil"}
