DB[570226]={D="Augmente l'efficacité de vos balises de 50%.",DE="Increases the effectiveness of your Wards by 50%.",N="Protection contre la peste"}
aura(570231, "Reverse the next spell cast on you within 3 sec, reflecting it back to its caster.\nReversing a spell in this way drains 150+16.0 Points Per Level+SP*.2 of the attacker's mana.", "Annulez le prochain sort lancé sur vous dans les 3 s, le renvoyant à son lanceur.\nInverser un sort de cette manière draine 150+16,0 points par niveau+SP*,2 du mana de l'attaquant.")
aura(570235, "Level 40 Passive\nBorn in Blood now stacks 1 additional time.", "Passif niveau 40\nNé dans le sang se cumule désormais 1 fois supplémentaire.")
aura(570236, "Your Smash now regenerate 25% of your maximum Energy.", "Votre Smash régénère désormais 25% de votre Énergie maximum.")
aura(570242, "Level 50 Passive\nDamage dealt by Throw Weapon now scales with your Agility.", "Passif niveau 50\nLes dégâts infligés par Throw Weapon s'adaptent désormais à votre Agilité.")
aura(570336, "Level 20 Passive\nIncreases your spell damage by 25% of your Intellect and your haste rating by 20% of your Intellect.", "Passif niveau 20\nAugmente les dégâts de vos sorts de 25% de votre Intelligence et votre taux de hâte de 20% de votre Intelligence.")
aura(570338, "Level 20 Passive\nIncreases your spell penetration by 20, scaling with your level.", "Passif niveau 20\nAugmente la pénétration de vos sorts de 20, en fonction de votre niveau.")
aura(570713, "Level 40 Passive\nMelee attacks now reduce the cooldown of Brace by 1 sec.", "Passif niveau 40\nLes attaques de mêlée réduisent désormais le temps de recharge de Brace de 1 seconde.")
DB[570722]={D="Lancer Décharge restaure désormais 5% de mana en plus.",DE="Casting Discharge now restores 5% more mana.",N="Statique concentrée"}
