DB[572416]={D="Augmente l'efficacité de vos Aspects de 20 % et leurs chances de se déclencher de 10 %.",DE="Increases the effectiveness of your Aspects by 20% and their chance to trigger by 10%.",N="Maîtrise des Aspects"}
DB[572527]={D="Réduit le temps de recharge de Vagues du temps de 4 secondes.",DE="Reduces the cooldown of Waves of Time by 4 sec.",N="Marche temporelle"}
DB[572538]={D="Augmente l'efficacité de l'augmentation de l'Éther de 50 %.",DE="Increases the effectiveness of Aether Augmentation by 50%.",N="La fonction avant la forme"}
DB[572545]={D="Pendant que |cffffffffAugmentation d'éther|r est active, tous les 4 |cffffffffTir de ferraille|r vous confèrent désormais |cffffffffBrillance innée|r.\n\n|cffffffffBrillance innée|r\nVotre prochain |cffffffffTir de ferraille|r a 5 m de portée supplémentaire, inflige 15 % de dégâts supplémentaires et draine $s1 de mana à votre cible. Dure $d.",DE="While Aether Augmentation is active, every 4th Scrap Shot now grants you Innate Brilliance.\n\nInnate Brilliance\nYour next Scrap Shot has 5 yds increased range, deals 15% increased damage, and drains $s1 of your target's mana. Lasts $d.",N="Brillance innée"}
aura(572546, "Increases your melee haste by 5% and expertise by 5.", "Augmente votre hâte en mêlée de 5% et votre expertise de 5.")
aura(572547, "Level 30 Passive\nIncreases the effectiveness Righteous Upheaval gains per trigger of Zealotry by 100%.", "Passif niveau 30\nAugmente l'efficacité des gains de Righteous Upheaval par déclenchement de Zealotry de 100 %.")
DB[572548]={D="Augmente les dégâts des armes infligés par le fanatisme de 10%.",DE="Increases the Weapon Damage dealt by Zealotry by 10%.",N="Sermon des lames"}
DB[572554]={D="Augmente les dégâts des armes infligés par le fanatisme de 20%.",DE="Increases the Weapon Damage dealt by Zealotry by 20%.",N="Sermon des lames"}
