DB[706896]={D="|cffffffffMâchoire du destructeur|r augmente désormais les dégâts de votre prochaine |cffffffffSouffle|r contre la cible de $802107s2% pendant $/1000;s1 sec.",DE="Increases the damage of Destroyer's Maw by 20%.",N="Sceptre de l'Aspect fou"}
aura(706904, "Build a Repulsion Unit that periodically knocks nearby enemies back every 5 sec for 20 sec.", "Construisez une unité de répulsion qui repousse périodiquement les ennemis proches toutes les 5 s pendant 20 s.")
DB[706909]={D="Les sorts qui consomment |cffffffffRunes du Vide|r infligent désormais 30 % de dégâts supplémentaires par rapport aux dégâts initiaux à la cible sur $706910d.",DE="Every 3rd Horrorbolt cast causes your next successful Horrorbolt to deal an additional 50% of the initial damage to the target over 3 sec.",N="Pourriture béante"}
DB[706911]={D="Les dégâts infligés par Regard de C'Thun ont désormais 15 % de chances de générer un portail du Vide qui lance Regard de C'thun, Horrorbolt ou Rayon d'oblitération avant de disparaître.",DE="Damage dealt by Gaze of C'Thun now has a 15% to chance to spawn a void portal that casts either Gaze of C'thun, Horrorbolt, or Obliteration Beam before disappearing.",N="Profondeurs de la folie"}
DB[706915]={D="Augmente vos chances de toucher de 3 % et réduit de 15 % la menace générée par les sorts de dégâts Ombre.",DE="Increases your chance to hit by 3% and reduces threat generated by Shadow damage spells by 15%.",N="Nature rusée"}
DB[706917]={D="Augmente la hâte de vos sorts de 4 % et vous permet de régénérer un mana égal à 1 % de votre mana manquant toutes les 10 s.",DE="Increases your spell haste by 4% and causes you to regenerate mana equal to 1% of your missing mana every 10 sec.",N="Idole inquiétante"}
DB[706921]={D="Augmente le bonus de dégâts apporté par vos Murmures Corrupteurs de 5%.",DE="Increases the damage bonus provided by your Corrupting Whispers by 5%.",N="Jeu déloyal"}
DB[706926]={D="Vous soignez désormais l'allié le plus blessé affecté par |cffffffffSang noir|r à hauteur de $s1% des dégâts de vos attaques automatiques.",DE="You now heal the lowest health ally affected by Black Blood for $s1% of your auto attack damage.",N="Fanion de l'ombre"}
DB[706928]={D="Augmente l'efficacité de vos murmures de 25%.",DE="Increases the effectiveness of your Whispers by 25%.",N="Mots de l'ombre"}
DB[706937]={D="Réduit le temps d'incantation de Prière de Shadra de 10 % et réduit de 35 % le retard d'incantation subi lorsque des attaques vous infligent des dégâts.",DE="Reduces the cast time of Shadra's Prayer by 10% and your spell pushback suffered from damaging attacks by 35%.",N="Don de Shadra"}
DB[706938]={D="Augmente la durée du Baume de Shadra, de la Brume réparatrice et de la Prière de Shadra de 3 s.",DE="Increases the duration of Shadra's Balm and Mending Mist and Shadra's Prayer by 3 sec.",N="Renouveau ophidien"}
aura(706940, "Level 30 Passive\nTeaches you Weaver Form.\nWeaver Form\nShapeshift into Weaver Form, allowing your periodic effects to benefit from spell haste, reducing spell pushback suffered from damaging attacks by 70%, and giving periodic damage dealt a 5% chance to restore 5% of your missing mana.\nCannot use healing spells while in Weaver Form.", "Passif niveau 30\nVous apprend la forme du tisserand.\nForme de tisserand\nChangez de forme en forme de tisserand, permettant à vos effets périodiques de bénéficier de la hâte des sorts, réduisant de 70 % le recul des sorts subis par les attaques dommageables et donnant aux dégâts périodiques infligés 5 % de chances de restaurer 5 % de votre mana manquant.\nImpossible d'utiliser des sorts de soins en forme de tisserand.")
DB[706942]={D="Augmente la durée de vos effets de dégâts périodiques Vénomancien de 3 s.",DE="Increases the duration of your Venomancer periodic damage effects by 3 sec.",N="Prolongation"}
DB[706945]={D="|cffffffffÉtreinte du serpent|r rafraîchit désormais 2 charges de |cffffffffDon de Shadra|r.",DE="Your Serpent's Fang now refreshes a charge of Alkahest.",N="Mélioration"}
DB[706948]={D="Infliger Ombre de dégâts augmente désormais les dégâts que la cible subit de la part de vos guerriers squelettiques de 1 % pendant 10 s, cumulable 10 fois.",DE="Dealing Shadow damage now increases the damage the target takes from your Skeletal Warriors by 1% for 10 sec, stacking 10 times.",N="Marque fétide"}
DB[706955]={D="Augmente la contribution d'armure de vos objets en mailles de 25%.",DE="Increases your Armor contribution from mail by 25%.",N="Chitine enchantée"}
DB[706956]={D="Chaque fois que vous générez un champignon, vous réduisez désormais le temps de recharge de Decay de 1 seconde.",DE="Each time you spawn a Mushroom, you now reduce the cooldown of Decay by 1 sec.",N="Orateur prophétique"}
aura(706962, "Inject an enemy with a devastating venom, dealing 16+0+NatP*0.2 Nature damage every 3 sec for 21 sec. Damage is dealt slowly at first, and builds up over time.", "Injecte à un ennemi un venin dévastateur, infligeant 16+0+NatP*0,2 points de dégâts de Nature toutes les 3 s pendant 21 s. Les dégâts sont infligés lentement au début et s'accumulent avec le temps.")
aura(707001, "Damage dealt by Undead minions has a 10% chance to blast up to 3 nearby enemies for 71*$+SP*0.3 Plague damage.", "Les dégâts infligés par les serviteurs morts-vivants ont 10 % de chances de faire exploser jusqu'à 3 ennemis proches pour 71*$+SP*0,3 dégâts de peste.")
DB[707006]={D="Augmente les dégâts de Lichfrost de 10% et ses Puissance runique générés de 25%.",DE="Increases the damage of Lichfrost by 10% and its Runic Power generated by 25%.",N="Légion d'os"}
aura(707007, "Beckon the restless dead to rise and march forward.\nWhen they reach an enemy they explode, dealing 700*$+SP*.75 Plague damage to nearby enemies and slowing their movement speed by 70% for 3 sec.", "Faites signe aux morts agités de se relever et d’avancer.\nLorsqu'ils atteignent un ennemi, ils explosent, infligeant 700*$+SP*,75 dégâts de peste aux ennemis proches et ralentissant leur vitesse de déplacement de 70 % pendant 3 s.")
aura(707028, "Reduces the cooldown of Implosion by 10 sec and its Rage cost by 5.", "Réduit le temps de recharge d'Implosion de 10 s et son coût en Rage de 5.")
DB[707053]={D="|cffffffffAppel d'éclair|r rembourse désormais 10 |cFFFFFFFFStatique|r.",DE="Casting Discharge now increases your movement speed by 20% for 6 sec, stacking 2 times.",N="Changement de cap"}
DB[707054]={D="Augmente les dégâts et les chances de coup critique d'Électrocution de 10 %.",DE="Increases the damage and critical strike chance of Electrocute by 10%.",N="Secousse"}
DB[707055]={D="Augmente les chances de coup critique de Call Lightning et Arm of Thorim de 15% contre les cibles affectées par votre Volt.",DE="Increases the critical strike chance of Call Lightning and Arm of Thorim by 15% against targets affected by your Volt.",N="Fulmination"}
aura(707064, "Level 10 Passive\nAuto attacks while wielding a two-handed weapon now have a 25% chance to unleash Grasp of the Undying, leeching 10+1.2 Points Per Level+SP*0.15+AP*.1 health from the target.", "Passif niveau 10\nLes attaques automatiques lorsque vous brandissez une arme à deux mains ont désormais 25 % de chances de libérer Emprise de l'immortel, drainant 10+1,2 points par niveau + SP*0,15+AP*,1 points de vie de la cible.")
DB[707067]={D="Noctis Blade consomme désormais Ombre Brand pour infliger 50% de dégâts supplémentaires.",DE="Noctis Blade now consumes Shadow Brand to deal 50% increased damage.",N="Roi de la Nuit"}
aura(707072, "Level 10 Passive\nAllows you to dual wield and to wield a Two-Handed Mace, Sword, or Polearm in each hand and your chance to hit is increased by 6%.", "Passif niveau 10\nVous permet d'utiliser deux armes et de manier une masse, une épée ou une arme d'hast à deux mains dans chaque main et vos chances de toucher sont augmentées de 6 %.")
DB[707077]={D="Les soins effectués appliquent |cffffffffFoi|r pour $804405d.@s:804405:0@",DE="Direct healing done now increases the target's Armor by 10% for 20 sec.",N="Foi"}
DB[707078]={D="Pendant la journée, vous infligez désormais 10 % de dégâts Sacré supplémentaires et subissez 10 % de dégâts périodiques réduits.",DE="During the day you now deal 10% more Holy damage and take 10% reduced periodic damage.",N="Debout face aux ténèbres"}
DB[707079]={D="Augmente la rage générée par |cffffffffAnoint|r de $/10;s1 et augmente également vos chances de coup critique Saint de $524998s1% pendant $524998d.",DE="Casting Hammer of Kings now also increases your critical strike chance by 10% for 10 sec.",N="Le roi élu"}
DB[707081]={D="Accomplir votre vœu libère désormais une chaîne de lumière sur votre cible, infligeant 81+6,0 points par niveau+HolP*0,23+AP*,1 Sacré de dégâts, puis rebondissant sur jusqu'à 5 ennemis supplémentaires, infligeant des dégâts réduits à chaque frappe.",DE="Fulfilling your Vow now unleashes a chain of light at your target, dealing 81+6.0 Points Per Level+HolP*0.23+AP*.1 Holy damage and then bouncing to up to 5 additional enemies, dealing reduced damage with each strike.",N="Renforcement solaire"}
aura(707104, "Create a macro-gravity zone at target location for 8 sec.\nEnemies within the zone have their movement speed slowed by 50% and gain 1 stack of Macro-Gravity every 0.5 sec.\nMacro-Gravity\nAt 6 stacks, the affected enemy will be stunned for 6 sec.", "Créez une zone de macrogravité à l'emplacement cible pendant 8 secondes.\nLes ennemis dans la zone voient leur vitesse de déplacement ralentie de 50 % et gagnent 1 charge de Macro-Gravité toutes les 0,5 s.\nMacro-gravité\nÀ 6 charges, l'ennemi affecté sera étourdi pendant 6 s.")
DB[707113]={D="Permet à Expurgation de se cumuler un temps supplémentaire et augmente la portée de vos sorts de Mort de 20%.",DE="Allows Expunge to stack an additional time and increases the range of your Death spells by 20%.",N="Toucher de la mort"}
aura(707115, "Level 40 Passive\nIncreases the effectiveness of your Mechsuit by 100%.", "Passif niveau 40\nAugmente l'efficacité de votre Mechsuit de 100%.")
aura(707116, "Damage dealt by Spectral Scythes and Spectral Wardens now reduces the cooldown of Spectral Warden by 0.5 sec.", "Les dégâts infligés par les Faux spectrales et les Gardiens spectraux réduisent désormais le temps de recharge de Gardien spectral de 0,5 seconde.")
DB[707126]={D="Réduit le temps de recharge de Spellburn de 4 s et augmente sa durée de 1 s.",DE="Reduces the cooldown of Spellburn by 4 sec and increases its duration by 1 sec.",N="Brûlure constante"}
DB[707137]={D="Réduit le temps de recharge de |cffffffffBouclierforge|r de $/1000;s1 sec.",DE="Blocking an attack while Raise Shield is active now increases your maximum health by 290+10.2 Points Per Level+Sta*.1+AP*.11 for 15 sec.",N="Résilient"}
DB[707149]={D="Augmente le temps de recharge de Speed ​​Rune de 30 secondes, mais elle applique désormais la furtivité aux alliés qui marchent sur le chemin pendant toute la durée.",DE="Increases the cooldown of Speed Rune by 30 sec, but it now applies stealth to allies who walk on the pathway for the duration.",N="Secrets élémentaires"}
DB[707150]={D="Permet à l'effet de |cffffffffPierre runique : Calligraphie élémentaire|r de s'accumuler une fois de plus.",DE="Each strike from Hurricane is now guaranteed to apply Weapon Engraving: Water or Weapon Engraving: Ice to your target while they are active.",N="Runes d'eau"}
DB[707157]={D="Dans Runic Tattoos: Earth, vous récupérez désormais 3% de votre vie maximale toutes les 4 secondes et vous devenez immunisé contre les renversements.",DE="While in Runic Tattoos: Earth, you now heal for 3% of your maximum health every 4 sec and you become immune to knockbacks.",N="Pétroglyphe de pierre"}
aura(707162, "Tools:\nFire Totem\nSummon a mimic ward for 12 sec. For the duration when you cast Malefic Wrath and Loa's Brew the ward will also cast it on your target.\nMimic Wards can be active alongside other Wards.", "Outils :\nTotem de Feu\nInvoque une protection mimique pendant 12 s. Pendant la durée pendant laquelle vous lancez Courroux maléfique et Bière de Loa, la protection les lancera également sur votre cible.\nLes Mimic Wards peuvent être actifs aux côtés d’autres Wards.")
DB[707168]={D="Augmente la durée de Mimic Ward et Spirits de 4 sec.",DE="Increases the duration of Mimic Ward and Spirits by 4 sec.",N="Gare au vaudou"}
aura(707173, "Increases the amount that Earthquake slows enemies by 30%.", "Augmente la quantité de tremblement de terre qui ralentit les ennemis de 30 %.")
DB[707204]={D="Augmente tous les dégâts que vous infligez aux ennemis affectés par votre |cffffffffVolt|r de $707057s1% pendant $707057d.",DE="While Lightning Cage is active your Magic Damage taken is now reduced by 25% and you are unable to be hit by ranged attacks.",N="Barrière de tempête"}
DB[707207]={D="|cffffffffRage barbare|r supprime désormais également la peur, les effets de racine et de réduction de mouvement, et vous rend immunisé contre ces effets pendant $/1000;S1 sec.",DE="Increases the range of your Whirling Advance by 3 yds.",N="Marche en avant"}
aura(707209, "Transform into a malignant spirit for 30 sec, allowing you to cast Malefic Wrath and Bad Juju while moving, and periodically granting you a Spirit every 2 sec.\nSpirit\nRegenerates 2+ health and mana, repeating every 4 sec for 12 sec, stacking 5 times.", "Transformez-vous en esprit malin pendant 30 s, vous permettant de lancer Colère maléfique et Bad Juju tout en vous déplaçant, et vous accordant périodiquement un Esprit toutes les 2 s.\nEsprit\nRégénère 2+ points de vie et de mana, en se répétant toutes les 4 s pendant 12 s, cumulable 5 fois.")
DB[707212]={D="Lorsque vous soignez avec Loa's Brew, vos effigies soigneront désormais un allié supplémentaire à moins de 20 mètres pour 35 % des soins effectués, en donnant la priorité aux alliés dont la vie est faible.",DE="When you heal with Loa's Brew your Effigies will now heal an additional ally within 20 yds for 35% of the healing done, prioritizing allies with low health.",N="Secrets de la jungle"}
aura(707217, "Level 40 Passive\nConsuming Embers now has a 30% chance to reset the cooldown of Destroyer's Maw and Firefall and grant you Legacy of Deathwing.\nLegacy of Deathwing\nYour next Destroyer's Maw or Firefall within 10 sec is instant cast and free of cost.", "Passif niveau 40\nConsommer des braises a désormais 30 % de chances de réinitialiser le temps de recharge de la Gueule du destructeur et de la Chute de feu et de vous accorder l'Héritage d'Aile de mort.\nL'héritage d'Aile de mort\nVotre prochain Destructeur's Maw ou Firefall dans les 10 secondes est lancé instantanément et gratuitement.")
DB[707224]={D="Votre mycose enrage désormais vos Fongarian pendant 6 s, augmentant ses dégâts et sa vitesse d'attaque de 30 % pendant 6 s.",DE="Your Mycosis now enrages your Fungarians for 6 sec, increasing its damage and attack speed by 30% for 6 sec.",N="Rage de Venoxis"}
aura(707232, "Your Suffuse now increases your movement speed by 20%.", "Votre Suffuse augmente désormais votre vitesse de déplacement de 20%.")
DB[707233]={D="Réduit le temps de recharge de |cffffffffWeb Wrap|r de $/1000;s1 sec.",DE="Periodic damage now has a 5% chance to cause you to launch webs at your target, wrapping them in a Suffocating Coil.\nSuffocating Coil\nLaunch a beam of webbing at an enemy, inflicting 91*$+NatP*0.12 Nature damage every 1 sec for 4 sec.\nAfter 4 sec, if Spore is active on the target, drop a Mushroom below them that will explode after 2 sec, dealing 303+46.0 Points Per Level+NatP*.125 Nature damage to all enemies within 5 yds.",N="Anneaux suffocants"}
DB[707237]={D="Lorsque vous utilisez |cffffffffLancer de bombe|r, votre |cffffffffTourelle sentinelle|r libère des flammes sur votre cible, infligeant $s1 dégâts de Feu aux ennemis sur une ligne de 30 m.",DE="When you Bomb Toss, your Sentry Turret unleashes flames on your target, dealing $s1 Fire damage to enemies in a 30 yd line.",N="Lancer de flammes"}
DB[707239]={D="Les dégâts infligés par l'augmentation explosive et l'augmentation du traceur ont désormais 50 % de chances d'appliquer une charge supplémentaire de Napalm aux ennemis.\nNapalm\nLes dégâts de feu que vous subissez sont augmentés et les soins reçus sont réduits de 3 % pendant 8 s. Se cumule 10 fois.",DE="Damage dealt by Explosive Augmentation and Tracer Augmentation now has a 50% chance to apply an additional stack of Napalm to enemies.\nNapalm\nFire Damage taken by you is increased and healing received reduced by 3% for 8 sec. Stacks 10 times.",N="Crimes de guerre"}
DB[707240]={D="Lorsque vous atteignez 5 stacks de Napalm sur une cible, vous rafraîchissez 1 charge de Build: Firepot Drone.",DE="When you reach 5 stacks of Napalm on a target you refresh 1 charge of Build: Firepot Drone.",N="Grenadier"}
DB[707244]={D="Lorsque le lance-roquettes est utilisé sur des ennemis affectés par Sticky Bomb, il est désormais garanti de frapper de manière critique.",DE="When Rocket Launcher is used on enemies affected by Sticky Bomb it is now guaranteed to critically strike.",N="Lancement surprise !"}
DB[707246]={D="Sparked and Ready augmente désormais également les chances de coup critique du lance-roquettes de 20 %.",DE="Sparked and Ready now also increases the critical strike chance of Rocket Launcher by 20%.",N="Mèche courte"}
aura(707249, "Every 4th Scrap Shot now causes your next Scrap Shot within 15 sec to deal 25% increased damage.", "Tous les 4 tirs de ferraille, votre prochain tir de ferraille dans les 15 secondes inflige désormais 25 % de dégâts supplémentaires.")
DB[707252]={D="Augmente la portée du lance-roquettes de 10 mètres.",DE="Increases the range of Rocket Launcher by 10 yds.",N="Méga-lunette"}
DB[707253]={D="Augmente les dégâts critiques du lance-roquettes de 10%.",DE="Increases the critical damage of Rocket Launcher by 10%.",N="Lunette de démolition"}
DB[707254]={D="Votre Scrap Shot ignore désormais 25 % du Armure de la cible lorsqu'il endommage des cibles en feu.",DE="Your Scrap Shot now ignores 25% of the target's Armor when damaging Burning targets.",N="Brise-tank"}
DB[707256]={D="Firepot Drone et Scrap Shot infligent désormais 2% de dégâts supplémentaires pour chaque charge de Napalm sur l'ennemi.\nNapalm\nLes dégâts de feu que vous subissez sont augmentés et les soins reçus sont réduits de 3 % pendant 8 s. Se cumule 10 fois.",DE="Firepot Drone and Scrap Shot now deal 2% increased damage for each stack of Napalm on the enemy.\nNapalm\nFire Damage taken by you is increased and healing received reduced by 3% for 8 sec. Stacks 10 times.",N="Drone d'assaut"}
aura(707257, "Build an Oil-Spill Pylon at target location for 10 sec, spilling oil in an 8 yd radius that reduces enemies movement speed by 60% and increases their Fire damage taken by you by 15%.\nSticky Bomb Explosions and Firepot Drone deal 20% increased damage to enemies inside.", "Construisez un pylône de déversement de pétrole à l'emplacement cible pendant 10 s, déversant du pétrole dans un rayon de 8 mètres, ce qui réduit la vitesse de déplacement des ennemis de 60 % et augmente les dégâts de feu que vous subissez de 15 %.\nLes explosions de bombes collantes et le drone Firepot infligent 20 % de dégâts supplémentaires aux ennemis à l’intérieur.")
DB[707258]={D="Construction : Spider Bomb crée désormais une Spider Bomb supplémentaire qui se précipite vers votre cible.",DE="Build: Spider Bomb now creates an additional Spider Bomb that rushes towards your target.",N="Duobombardiers"}
DB[707259]={D="Permet à |cffffffffSynergie mécanique|r de se cumuler 2 fois de plus, et utiliser |cffffffffLance-roquettes|r fait aussi tirer un |cffffffffLance-roquettes|r à votre |cffffffffTourelle sentinelle|r.\n\n|cffffffffSynergie mécanique|r\nAugmente les dégâts infligés de $s1% et la hâte de $s2%, cumulable $u fois, pendant $d.",DE="Allows Machine Synergy to stack 2 additional times and using Rocket Launcher now causes your Sentry Turret to also cast Rocket Launcher.\n\nMachine Synergy\nIncreases damage dealt by $s1% and haste by $s2%, stacking $u times, for $d.",N="Tourelles à roquettes"}
DB[707260]={D="Lancer |cffffffffBombe collante|r fait désormais tirer vos 2 prochains |cffffffffTir de ferraille|r dans les 10 s 50 % plus vite et avec 25 % de dégâts supplémentaires.",DE="Casting Sticky Bomb now causes your next 2 Scrap Shots within 10 sec to cast 50% faster and deal 25% increased damage.",N="Répercussions"}
DB[707262]={D="Vos explosions de bombes collantes et votre bombe araignée infligent désormais 30 % de dégâts supplémentaires lorsqu'elles frappent une seule cible.",DE="Your Sticky Bomb Explosions and Spider Bomb now deal 30% increased damage when it strikes only 1 target.",N="Cible verrouillée"}
DB[707265]={D="Les dégâts infligés par vos tourelles sentinelles ralentiront désormais la vitesse de déplacement de l'ennemi de 15 % pendant 10 s, cumulable 3 fois.",DE="Damage dealt by your Sentry Turrets will now slow enemy movement speed by 15% for 10 sec, stacking 3 times.",N="Lance-bombes givrées"}
DB[707269]={D="Augmente les dégâts de Scrap Shot de 15% et augmente vos chances de toucher de 2%.",DE="Increases the damage of Scrap Shot by 15% and increases your chance to hit by 2%.",N="Balles incendiaires"}
aura(707271, "Level 30 Passive\nCasting Build: Spider Bomb now resets the cooldown of Bomb Toss and causes your next Bomb Toss within 15 sec to trigger no cooldown, global cooldown, or cost.", "Passif niveau 30\nConstruction de lancement : Spider Bombe réinitialise désormais le temps de recharge de Lancer de bombe et fait en sorte que votre prochain Lancer de bombe dans les 15 secondes ne déclenche aucun temps de recharge, aucun temps de recharge global ni aucun coût.")
aura(707273, "Level 30 Passive\nWhile Bombastic is active, your Bomb Tosses will additionally reduce the cooldown of Sticky Bomb by 1 sec.", "Passif niveau 30\nPendant que Bombastic est actif, vos lancers de bombes réduiront également le temps de recharge de Sticky Bomb de 1 seconde.")
DB[707277]={D="Lancer Scrap Shot ajoute désormais une charge de synergie de machines à votre familier actif et à votre tourelle sentinelle.\nSynergie des machines\nAugmente les dégâts infligés de 5 % et la hâte de 3 %, cumulable 3 fois, pendant 6 s.",DE="Casting Scrap Shot now adds a stack of Machine Synergy to your active pet and Sentry Turret.\nMachine Synergy\nIncreases damage dealt by 5% and haste by 3%, stacking 3 times, for 6 sec.",N="Synergie des machines"}
DB[707305]={D="Les Dégâts infligés avec |cffffffffDésolation|r et |cFFFFFFFFMassacre|r augmentent désormais les Dégâts de votre prochain |cffffffffFaucheur du destin|r de $704554s1%, cumulable $704554u fois, pendant $704554d.",DE="Wraithblade now deals an additional 100% Weapon Damage and its Runic Power cost is reduced by 20.",N="Spectre de sang"}
DB[707310]={D="|cffffffffBriseur de ligne|r inflige désormais 100 % de dégâts supplémentaires par rapport aux dégâts initiaux sur $706808d.",DE="Centurion Strike is now guaranteed to critically strike against enemies affected by Net Throw.",N="Bagarreur du corps-à-corps"}
aura(707317, "Increases the spell power scaling of Purifier's Edge and Fiery Judgement by 25%.", "Augmente la puissance des sorts de Lame du purificateur et Jugement ardent de 25 %.")
DB[707319]={D="Lancer Instinct restaure désormais également 40 Focalisation supplémentaires et garantit que vos 3 prochains perce-crânes ou assauts dans les 20 secondes infligeront un coup critique.\nDe plus, Instinct vous accorde désormais 10 % supplémentaires de votre Agilité en puissance d'attaque en mêlée.",DE="Casting Instinct now also restores 40 extra Focus and guarantees your next 3 Skullpiercers or Assaults within 20 sec to critically strike.\nIn addition, Instinct now grants you an additional 10% of your Agility as melee attack power.",N="Combattant instinctif"}
aura(707320, "Level 40 Passive\nIncreases your spell damage by 30% of your attack power and allows periodic damage dealt by Expulsion to critically strike.", "Passif niveau 40\nAugmente les dégâts de vos sorts de 30 % de votre puissance d'attaque et permet aux dégâts périodiques infligés par Expulsion de frapper de manière critique.")
DB[707325]={D="|cffffffffSouffle de Neltharion|r et |cffffffffBurst|r frappent désormais un ennemi supplémentaire et propagent |cffffffffBlaze|r à un maximum de $800834i ennemis dans un rayon de $800834a1 m.",DE="Your Aspect's Blessing now affects 2 additional casts of Echo of Nozdormu, but its cooldown is doubled, and its mana cost is increased by 50%.",N="Flammes du destin"}
DB[707329]={D="Utiliser |cffffffffTueur de dieu|r ou |cffffffffDon des Loas|r déclenchera désormais un effet supplémentaire en fonction de votre |cffffffffAvatar|r actif.\n\n|cffffffffWar Raptor|r : Réinitialise le temps de recharge de |cffffffffRage de Bethekk|r et fait en sorte que votre prochaine |cffffffffRage de Bethekk|r touche $706641s3 ennemis supplémentaires et inflige $706641s2% de dégâts supplémentaires pendant $706641d.\n\n|cffffffffPterrordax|r : Supprime le coût de vos 3 prochaines |cffffffffShadow Glaives|r et leur fait infliger 20% des dégâts infligés, s'accumulant $706445u fois, pendant $706445d.",DE="Transforms Call of Sseratus into Viper Ward.\nViper Ward\nSummons a powerful and fast-attacking Viper Ward at target location for 20 sec.\nViper Wards have a 50% chance to unleash a Hexfire Blast, dealing 216+1.0 Points Per Level+RAP*.15 Fire damage to an enemy.\nChance increased based on your ranged critical strike rating.",N="Garde de la vipère"}
DB[707331]={D="Votre Bad Juju et votre Hexfire frappent désormais 2 ennemis proches supplémentaires.\nShadowflare inflige désormais 50% de dégâts supplémentaires aux ennemis affectés par les fils du marionnettiste.\nFils du marionnettiste\nLes dégâts subis par le Féticheur stockent 15% de sa valeur. Lorsque l'effet prend fin, les dégâts stockés sont infligés instantanément.",DE="Your Bad Juju and Hexfire now strike 2 additional nearby enemies.\nShadowflare now deals 50% increased damage to enemies affected by Puppeteer's Threads.\nPuppeteer’s Threads\nDamage taken from the Witch Doctor stores 15% of its value. When the effect ends the damage stored is dealt instantly.",N="Effigie sombre"}
DB[707364]={D="Réduit le temps de recharge global de |cffffffffSacred Slam|r$?s805421[ et |cFFFFFFFFImpact zélé|r][] de $/1000;S1 sec.",DE="Casting Benediction now reduces the cost of your next Temple Guardian by 50% for 6 sec.",N="Gardien de la Lumière"}
DB[707367]={D="Permet aux dégâts périodiques infligés par |cffffffffDéchiquetage primal|r et |cffffffffMâchoire d'ours|r de porter des coups critiques.",DE="Casting Primal Shred now empowers your pet, causing its auto attacks to strike up to 4 nearby enemies for 21 sec.",N="Frénésie spirituelle"}
DB[707371]={D="Les soins critiques réduisent désormais les dégâts subis par un allié de $504102s1 % pendant $504102d.",DE="Adds 40% to the Armor contribution from items by Blood Shield.",N="Magie viscérale"}
DB[707380]={D="Réduit le temps de recharge de Tir incapacitant de 4 secondes.",DE="Reduces the cooldown of Crippling Shot by 4 sec.",N="Tirs mortels"}
DB[707382]={D="Permet à vos effets de dégâts périodiques de Venomancer de bénéficier de la hâte des sorts et de porter des coups critiques.",DE="Critical strikes with Widow's Kiss now apply 1 additional Brood Mark.",N="Essence de décomposition"}
aura(707385, "Casting Libram of Tenacity now also heals you for 20% of your maximum health.", "Lancer Libram de ténacité vous soigne désormais également de 20 % de votre vie maximale.")
DB[707389]={D="Les coups critiques avec Barbed Spear confèrent désormais Né dans le sang.\nNé dans le sang\nLe combat alimente votre vitalité, en restaurant 15 points de vie et 9 Énergie en 3 s.",DE="Critical strikes with Barbed Spear now grants Born in Blood.\nBorn in Blood\nBattle fuels your vitality, restoring 15 health and 9 Energy over 3 sec.",N="Berserker furieux"}
aura(707390, "Level 30 Passive\nCritical strikes with Gore now generate 1 additional Demonfire.", "Passif niveau 30\nLes coups critiques avec Gore génèrent désormais 1 Feu démoniaque supplémentaire.")
aura(707391, "Melee damage dealt now has a 20% chance to strike 2 additional times for 30% of the damage dealt as Holy Damage.", "Les dégâts de mêlée infligés ont désormais 20 % de chances de frapper 2 fois supplémentaires pour 30 % des dégâts infligés sous forme de dégâts Sacré.")
DB[707395]={D="Lorsque |cffffffffSticky Bomb|r inflige des dégâts, le prochain |cffffffffCoup de clé|r utilisé dans $504526d réinitialise le temps de recharge de |cffffffffCoup du ferrailleur|r.",DE="Casting Mechsuit abilities now causes your pet to enter a haywired state for 6 sec.\nHaywired State!\nAuto attacks now zap up to 10 nearby enemies for 155+3.0 Points Per Level+AP*.35 Stormstrike Damage and damaged enemies take 20% increased damage from your summons.",N="État détraqué !"}
DB[707398]={D="Augmente le taux de tic-tac et les soins effectués lors de la reconstruction des nanobots de 20 %.",DE="Increases the tick rate and healing done of Nanobot Reconstruction by 20%.",N="Technologie de pointe"}
DB[707403]={D="Dégâts infligés par Mechsuit : Combustion et Mechsuit : Laser Beam ont désormais 40 % de chances de frapper 2 fois supplémentaires pour 30 % des dégâts infligés.",DE="Damage dealt by Mechsuit: Combustion and Mechsuit: Laser Beam now have a 40% chance to strike 2 additional times for 30% of the damage dealt.",N="Surcharge"}
aura(707405, "Increases the spell power scaling of Malefic Wrath, Shadowflare, and Bad Juju by 20%.", "Augmente la puissance des sorts de Maléfique Wrath, Shadowflare et Bad Juju de 20 %.")
aura(707407, "Your Grasp of the Undying now strikes 2 additional nearby enemies.", "Votre Emprise de l'immortel frappe désormais 2 ennemis proches supplémentaires.")
DB[707410]={D="Les Dégâts infligés par |cffffffffVolée de haches|r réduisent désormais le temps de Recharge de |cffffffffLancer perçant|r de $/1000;503629s1 sec.",DE="Casting Unbridled Rage now grants you 30 Energy and it now also removes the Energy cost of your Spirit spells while active.",N="Esprit enragé"}
DB[707413]={D="Vos Palm Sigils affectent désormais 1 instance de dégâts supplémentaire.",DE="Your Palm Sigils now affect 1 additional instance of damage.",N="Éléments en furie"}
aura(707414, "Activating Dawn now reduces the cooldowns of Radiance, Valkyr's Calling, and Sunslam by 10%.", "L'activation de Dawn réduit désormais les temps de recharge de Radiance, Valkyr's Calling et Sunslam de 10 %.")
DB[707416]={D="Vos boules de feu Gangre utilisées avec l'actif Gangreforgé infligent désormais 30 % de dégâts supplémentaires.",DE="Your Fel Fireballs used with Felforged active now deal 30% increased damage.",N="Flétrissure"}
DB[707417]={D="Entrer |cffffffffElude|r génère 1 |cffffffffPoint d'archerie|r toutes les $704321t1 sec pendant $704321d.",DE="Increases your melee and ranged haste by 5%.",N="Mains habiles"}
DB[707418]={D="Les dégâts infligés par |cffffffffFlank|r et |cffffffffFlèche sylvestre|r invoquent désormais un |cffffffffFaucon de guerre|r pour vous aider au combat pour $800251d.",DE="Reduces the cooldown of Survival Potion by 25%.",N="Spécialiste de la survie"}
DB[707423]={D="Les coups critiques avec |cffffffffSpellwrath|r génèrent $800957s1% de mana maximum toutes les $804103t2 secondes pour $804103d.",DE="Casting Runeshroud now increases your movement speed by 75% for 3 sec.",N="Déferlement runique"}
DB[707429]={D="|cffffffffL'emprise de l'Empire|r invoque maintenant un |cFFFFFFFFTentacule de N'zoth|r sous vous.",DE="Your Mass Nightmare now triggers a 60 sec reduced cooldown when used at or above 80 Insanity.",N="Vide accablant"}
DB[707430]={D="|cFFFFFFFFDiscordance|r s'applique désormais à |cFFFFFFFFÉrosion magique|r.@s:570060:0@",DE="Transforms your Wand of Time into Timerend.\nTimerend\nRend the fabric of time, dealing 30 Chromatic Damage over 6 sec.",N="Déchire-temps"}
aura(707432, "Level 30 Passive\nYour critical heals now grant allies Replenishment.\nIn addition, 20% of your mana regeneration continues while in combat.\nReplenishment\nRestores 1% maximum mana every 5 sec to allies within 100 yds for 15 sec.", "Passif niveau 30\nVos soins critiques accordent désormais de la réapprovisionnement à vos alliés.\nDe plus, 20 % de votre régénération de mana se poursuit pendant le combat.\nRéapprovisionnement\nRestaure 1 % de mana maximum toutes les 5 s aux alliés à moins de 100 mètres pendant 15 s.")
DB[707433]={D="Augmente le taux de tick de Mercy de 50 %, mais augmente son coût en mana de 100 %.",DE="Increases the tick rate of Mercy by 50%, but increases its mana cost by 100%.",N="Brise-flétrissure"}
DB[707435]={D="Les dégâts infligés par Tourment de Taldaram ont désormais 20 % de chances de se rompre intérieurement, ce qui lui permet d'infliger ses dégâts une fois de plus à tous les ennemis proches de la cible.",DE="Damage dealt by Taldaram's Torment now has a 20% chance to internally rupture, causing it to deal its damage an additional time to all enemies near the target.",N="Sang maudit"}
DB[707444]={D="|cffffffffFelstrikes|r vous soignent désormais pour un montant égal aux dégâts infligés.",DE="Level 30 Passive\nCasting Carve now makes your next Fel Fireball instant cast and causes it to strike 1 additional enemy near the primary target based on how long you channeled, up to a maximum of 10 enemies, dealing less damage with each target struck.",N="Équarrisseur de gouffre-feu"}
DB[707451]={D="Réduit les soins prodigués par Inferno de 20 %, mais augmente ses chances de se déclencher de 50 %.",DE="Reduces the healing done by Inferno by 20%, but increases its chance to trigger by 50%.",N="Bénédiction du brasier"}
DB[707455]={D="Le Chasseur de mort utilisé contre une cible ayant moins de 20 % de vie se réappliquera désormais à la fin de sa durée jusqu'à sa mort ou jusqu'à ce que 5 secondes s'écoulent.",DE="Deathchaser used against a target below 20% health will now reapply itself at the end of its duration until they die or until 5 sec passes.",N="Poursuite de la mort"}
DB[707460]={D="Lorsque vous activez un Palm Sigil, vous êtes désormais assuré d'effectuer un coup critique qui inflige 20 % de dégâts critiques supplémentaires pendant 10 s ou vos 3 prochaines attaques.",DE="When you active a Palm Sigil, you are now guaranteed to critically strike for 20% increased critical damage for 10 sec or your next 3 attacks.",N="Codex terrestre"}
DB[707463]={D="Lancer Phase Out invoque désormais 10 clones de vous-même qui courent dans une direction aléatoire pendant 5 s.\nLes clones de faille explosent périodiquement, infligeant 1+0,0 points par niveau + AP*.195 Arcanes de dégâts à tous les ennemis à moins de 5 mètres d'eux.",DE="Casting Phase Out now summons 10 clones of yourself that run in a random direction for 5 sec.\nRift Clones periodically explode dealing 1+0.0 Points Per Level+AP*.195 Arcane damage to all enemies within 5 yds of them.",N="Clones de faille"}
DB[707479]={D="Les dégâts infligés par Aspect du temps vous soignent désormais à hauteur de 200 % des dégâts infligés.",DE="Damage dealt by Aspect of Time now heals you equal to 200% of the damage dealt.",N="Bénédiction du porteur de vie"}
DB[707482]={D="Augmente les chances de déclencher Fired Up de 20%.",DE="Increases the chance to trigger Fired Up by 20%.",N="Rôti vif"}
DB[707493]={D="Lancer Gueule du destructeur confère désormais 2 charges de Flamecasting.\nFlamme\nAugmente la hâte de vos sorts de 5 % pendant 15 s. Se cumule 5 fois.\nLes applications supplémentaires n'actualisent pas la durée.",DE="Casting Destroyer's Maw now grants 2 stacks of Flamecasting.\nFlamecasting\nIncreases your spell haste by 5% for 15 sec. Stacks 5 times.\nAdditional applications do not refresh duration.",N="Flammes des Aspects"}
DB[707494]={D="Réduit le temps de recharge d'Éruption de 30 secondes.",DE="Reduces the cooldown of Eruption by 30 sec.",N="Montagnard de Rochenoire"}
DB[707503]={D="La durée de Blaze est désormais augmentée de 1 seconde pour chaque braise que vous possédez lorsque vous la lancez.",DE="The duration of Blaze is now increased by 1 sec for each Ember you have when you cast it.",N="Brûlure perpétuelle"}
DB[707504]={D="Chaque Esprit actif vous donne 15 % de chances lorsque vous lancez Flèche Maléfique de générer un Esprit supplémentaire.\nEsprit\nRégénère 2+ points de vie et de mana, en se répétant toutes les 4 s pendant 12 s, cumulable 5 fois.",DE="Each active Spirit gives you a 15% chance when you cast Malefic Arrow to generate an additional Spirit.\nSpirit\nRegenerates 2+ health and mana, repeating every 4 sec for 12 sec, stacking 5 times.",N="Chasse aux esprits"}
DB[707505]={D="Augmente les chances de coup critique et les dégâts critiques de Hexfire de 25 %.",DE="Increases the critical strike chance and critical damage of Hexfire by 25%.",N="Courroux de Jin'do"}
DB[707513]={D="Votre Chaos Rush augmente désormais votre régénération Énergie de 10 % pendant 5 s, cumulable 2 fois.",DE="Your Chaos Rush now increases your Energy regeneration by 10% for 5 sec, stacking 2 times.",N="Gangremarcheur"}
DB[707514]={D="Réduit le temps de recharge de vos capacités sismiques de 2 secondes.",DE="Reduces the cooldown of your Seismic abilities by 2 sec.",N="Gardien de la Terre-Mère"}
DB[707515]={D="Lorsque Forme gouffre-feu est active, votre Seeking Flame n’a désormais plus de temps de recharge et génère un Feu démoniaque supplémentaire.",DE="While Hellfire Form is active, your Seeking Flame now has no cooldown and generates an additional Demonfire.",N="Grotesque"}
DB[707517]={D="Radiant Cascade est désormais assuré de frapper de manière critique les alliés affectés par Bless.",DE="Radiant Cascade is now guaranteed to critically strike on allies affected by Bless.",N="Force du soleil"}
DB[707528]={D="Accomplir votre vœu de grâce réduit désormais également le temps de recharge de la capacité déclenchée de 10 %.",DE="Fulfilling your Vow of Grace now also reduces the cooldown of the triggered ability by 10%.",N="Derniers vœux"}
DB[707534]={D="Chaque fois que vous générez une Dreamflower verte, vous recevez 1 charge de Highlander.\nHighlander\nÀ 3 charges, votre prochaine frappe de faucon dans les 10 sec inflige 25 % de dégâts supplémentaires et réduit les soins reçus de l'ennemi de 40 % pendant 8 s.",DE="Each time you spawn a green Dreamflower you are granted 1 stack of Highlander.\nHighlander\nAt 3 stacks, your next Falconstrike within 10 sec deals 25% increased damage and reduces the enemy's healing received by 40% for 8 sec.",N="Highlander"}
aura(707535, "Level 30 Passive\nIncreases your Fire spell damage by 50% of your Agility and your attack power by 100% of your Intellect.", "Passif niveau 30\nAugmente les dégâts de vos sorts de Feu de 50% de votre Agilité et votre puissance d'attaque de 100% de votre Intelligence.")
DB[707542]={D="Les dégâts infligés par Conduction ont désormais 60 % de chances d'invoquer un orbe de tonnerre.\nInvocation : Orbe de tonnerre\nInvoquez un orbe de tonnerre à l'emplacement cible pendant 16 s qui déclenche un choc orbe et génère 10 points de statique.",DE="Damage dealt by Conduction now has a 60% chance to summon a Thunder Orb.\nSummon: Thunder Orb\nSummon a Thunder Orb at the target location for 16 sec that triggers an Orb Shock and generates 10 Static.",N="Lieur de tempêtes"}
aura(707543, "Depletes 10 Static\nCommand your Air Elemental, causing its next instance of damage to unleash a flurry of air on your target, dealing (21*1000/3)*(59+3.5 Points Per Level+NatP*.2) Nature damage over 21 sec, and reducing their resistances by -(-20+ -0.1 Points Per Level), and increasing their Magic damage taken by 2%.", "Épuise 10 statique\nCommandez votre élémentaire d'air, provoquant sa prochaine instance de dégâts pour déclencher une rafale d'air sur votre cible, infligeant (21*1000/3)*(59+3,5 points par niveau+NatP*.2) dégâts de Nature en 21 sec, réduisant ses résistances de -(-20+ -0,1 points par niveau) et augmentant ses dégâts magiques subis de 2 %.")
aura(707546, "Casting Gale now causes your Air Elemental to cast Gale.\nAdditionally, you now emanate an aura around you, increasing the Armor of party and raid members by 390.\nDoes not stack with similar effects.", "Lancer Gale amène désormais votre élémentaire d’air à lancer Gale.\nDe plus, vous dégagez désormais une aura autour de vous, augmentant le Armure des membres du groupe et du raid de 390.\nNe se cumule pas avec des effets similaires.")
DB[707548]={D="Réduit le temps d'incantation d'Aeroblast de 0,3 seconde.",DE="Reduces the cast time of Aeroblast by 0.3 sec.",N="Courant d'air"}
DB[707551]={D="Augmente les dégâts de la Baguette du temps et de la Baguette de l'artificier de 10 %.",DE="Increases the damage of Wand of Time and Artificer's Wand by 10%.",N="Maître des baguettes"}
aura(707553, "Reduces the cooldown of Timerend by 2 sec and increases the duration of Decomposition by 3 sec.", "Réduit le temps de recharge de Timerend de 2 s et augmente la durée de Décomposition de 3 s.")
DB[707554]={D="Augmente les soins de Main d'Élune et Moonflow de 20%.",DE="Increases the healing of Hand of Elune and Moonflow by 20%.",N="Enseignements d'Élune"}
aura(707555, "Target an enemy and slip them into a pocket dimension for 5 sec, banishing them and making them immune to damage.\nActivate this ability again before the duration expires to choose a new location to place that enemy within 20 yds.", "Ciblez un ennemi et glissez-le dans une dimension de poche pendant 5 s, le bannissant et le rendant immunisé contre les dégâts.\nActivez à nouveau cette capacité avant l'expiration de la durée pour choisir un nouvel emplacement pour placer cet ennemi à moins de 20 mètres.")
aura(707556, "Reduces the cost of your spells by 5% and the chance for your spells to be dispelled by 10%.", "Réduit le coût de vos sorts de 5% et les chances que vos sorts soient dissipés de 10%.")
DB[707557]={D="Augmente les dégâts de Chromatic Shard, Melt Reality et Unmake de 15% contre les ennemis ralentis.",DE="Increases the damage of Chromatic Shard, Melt Reality and Unmake by 15% against slowed enemies.",N="Trou noir"}
DB[707560]={D="Temps de recharge instantané de 1,5 s. Votre barrage de géodes soigne désormais tous les alliés à moins de 20 mètres, à hauteur de 10 % des dégâts infligés.",DE="Instant1.5 sec cooldownYour Geode Barrage now heals all allies within 20 yds equal to 10% of the damage dealt.",N="Entraînement de druide"}
DB[707562]={D="Lorsque vous tuez un ennemi qui rapporte de l'expérience ou de l'honneur ou que vous frappez de manière critique avec des dégâts de Givre, vous gagnez désormais une charge de corps gelés.\nCorps gelés\nAugmente les dégâts de votre prochain Impact glaciaire de 3 % pendant 20 s, cumulable 10 fois.\nAtteindre 10 charges permet à votre prochain Impact Glacial de frapper de manière critique et d'infliger 50 % de dégâts supplémentaires.",DE="When you kill an enemy that yields experience or honor or critically strike with Frost damage you now gain a stack of Frozen Bodies.\nFrozen Bodies\nIncreases the damage of your next Glacial Impact by 3% for 20 sec, stacking 10 times.\nReaching 10 stacks causes your next Glacial Impact to critically strike for 50% increased damage.",N="Corps gelés"}
DB[707563]={D="Augmente vos dégâts de Nature de 5% et vos soins prodigués de 3%.",DE="Increases your Nature damage by 5% and healing done by 3%.",N="Jouer avec le poison"}
DB[707574]={D="Réduit le temps de recharge de Green Salve de 2 sec et augmente les soins prodigués à la fin de la durée de 50%.",DE="Reduces the cooldown of Green Salve by 2 sec and increases the healing done at the end of the duration by 50%.",N="Parchemins du culte du venin"}
DB[707583]={D="Augmente la durée d'Assaut de 6 s.",DE="Increases the duration of Onslaught by 6 sec.",N="Assaut sanglant"}
DB[707584]={D="Lancez rapidement 3 lancers de Berserker sur votre cible, puis projetez-vous en arrière sur une grande distance, infligeant 125 % de dégâts d'arme à distance, en fonction des modificateurs de la hache de Berserker.",DE="Quickly unleash 3 Berserker Throws at your target and then fling yourself back a great distance, dealing 125% Ranged Weapon Damage, scaling with modifiers to Berserker Axe.",N="Rancœur"}
aura(707588, "Critical strikes with Frost spells now refund 3% of your maximum mana.", "Les coups critiques avec les sorts Givre remboursent désormais 3% de votre mana maximum.")
DB[707604]={D="Votre Regard de C'Thun frappe désormais 1 ennemi proche supplémentaire.",DE="Your Gaze of C'Thun now strikes 1 additional nearby enemy.",N="Fendoir abyssal"}
DB[707606]={D="Lancer Righteous Upheaval ou Blade of Faith vous accorde désormais Serment : Retribution et démarre votre chaîne de serment.\nSerment : Rétribution\nDégâts critiques augmentés de 5%.",DE="Casting Righteous Upheaval or Blade of Faith now grants you Oath: Retribution and starts your Oath Chain.\nOath: Retribution\nCritical damage increased by 5%.",N="Châtiment fervent"}
DB[707613]={D="Chaque charge de Sunwalker augmente désormais les chances de coup critique de Shine de 3 %.",DE="Each stack of Sunwalker now increases the critical strike chance of Shine by 3%.",N="Puissance radieuse"}
DB[707614]={D="Augmente vos Rage générés par les dégâts infligés de 20%.",DE="Increases your Rage generated from damage dealt by 20%.",N="Tranchant dentelé"}
DB[707615]={D="Améliore certains de vos sorts grâce à la puissance du vent, transformant votre Conjure Storm en Updraft et Call Lightning en Aeroblast.\nUpdraft\nÉpuise 20 statiques\n2 charges, 10 secondes de recharge\nCréez un Updraft de 8 mètres à l'emplacement cible pendant 20 secondes.\nInflige (20*1000/2)*(16+0+NatP*0.0683) Dégâts de nature sur la durée aux ennemis dans le rayon.\nAugmente la vitesse de déplacement de 25 % pour les alliés dans le rayon.\nAeroblast\nÉpuise 50 statiques\nÉcrase un ennemi sous le poids des vents, lui infligeant 109+0+NatP*0,635 points de dégâts de Nature, puis une fois supplémentaire pour 40 % des dégâts infligés après 1 s.",DE="Enhances some of your spells with the power of the wind, tranforming your Conjure Storm into Updraft and Call Lightning into Aeroblast.\nUpdraft\nDepletes 20 Static\n2 Charges, 10 sec recharge\nCreate an 8 yd Updraft at the target location for 20 sec.\nDeals (20*1000/2)*(16+0+NatP*0.0683) Nature damage over the duration to enemies within the radius.\nIncreases movement speed by 25% for allies within the radius.\nAeroblast\nDepletes 50 Static\nCrush an enemy with the weight of the winds, dealing 109+0+NatP*0.635 Nature damage to them and then an additional time for 40% of the damage dealt after 1 sec.",N="Appel de la tempête"}
DB[707616]={D="Passif niveau 50\nLes dégâts infligés par Geode Barrage ou Geodes ont désormais 5% de chances de vous accorder Avatar terrestre pendant 5 secondes.\nSi Earthen Avatar est déjà actif, le déclenchement de cet effet prolongera la durée de 5 secondes.\nAvatar terrestre\nDevenez un avatar de la terre, augmentant les dégâts infligés, réduisant les dégâts subis de 15 % et augmentant votre hâte en mêlée de 20 % pendant 20 s.\nImmunisé contre les étourdissements, les immobilisations et les pièges pour toute la durée.\nUtilisable en étant étourdi.",DE="Level 50 Passive\nDamage dealt by Geode Barrage or Geodes now has a 5% chance to grant you Earthen Avatar for 5 sec.\nIf Earthen Avatar is already active triggering this effect will instead extend the duration by 5 sec.\nEarthen Avatar\nBecome an avatar of the earth, increasing your damage dealt and reducing your damage taken by 15%, and increasing your melee haste by 20% for 20 sec.\nImmune to stuns, roots, and snares for the duration.\nUsable while stunned.",N="Avatar de la montagne"}
aura(707617, "Level 40 Passive\nHealing with Mojo Beam now heals up to 3 of the lowest health nearby allies within 20 yds for 75% of the healing done.", "Passif niveau 40\nLes soins de Mojo Beam soignent désormais jusqu'à 3 des alliés proches ayant le moins de vie à moins de 20 mètres pour 75% des soins effectués.")
DB[707618]={D="Ascendance de tempête vous confère désormais également Seigneur de la foudre pendant 20 s.\nSeigneur de la foudre\nAugmente les dégâts infligés par Forked Lightning, Call Lightning et Electrocute de 30 % supplémentaires et permet à Electrocute de frapper 3 ennemis supplémentaires.",DE="Storm Ascendance now additionally grants you Lord of Lightning for 20 sec.\nLord of Lightning\nIncreases the damage dealt by Forked Lightning, Call Lightning, and Electrocute by an additional 30% and allows Electrocute to strike 3 additional enemies.",N="Seigneur de la foudre"}
DB[707619]={D="Dissiper un effet magique avec Stormbreaker vous soigne désormais de 3% de votre vie maximale.",DE="Dispelling a magic effect with Stormbreaker now heals you for 3% of your maximum health.",N="Conversion d'impulsion"}
DB[707620]={D="Passif niveau 50\nLes coups critiques infligés avec des dégâts directs vous appliquent désormais la Protogenèse, cumulable 10 fois.\nÀ 10 charges, toutes les charges sont consommées et le temps de recharge d'Expulsion est réduit de 3 secondes.\nProtogenèse\nSoigne 16 en 10 s.",DE="Level 50 Passive\nCritical strikes dealt with direct damage now apply Protogenesis to you, stacking 10 times.\nAt 10 stacks, all stacks are consumed and the cooldown of Expulsion is reduced by 3 sec.\nProtogenesis\nHeals for 16 over 10 sec.",N="Protogenèse"}
DB[707621]={D="Passif niveau 50\nAprès avoir utilisé Raise Shield, Advance ou Battle Rush, vous bénéficiez de la Haute Garde.\nHaute Garde\nVotre prochain coup puissant dans les 15 secondes ne déclenche aucun temps de recharge.",DE="Level 50 Passive\nAfter using Raise Shield, Advance or Battle Rush, you are granted High Guard.\nHigh Guard\nYour next Heavy Blow within 15 sec triggers no cooldown.",N="Haute garde"}
DB[707622]={D="Lorsque vous vous lancez sur un ennemi, vous soignez désormais 5% de votre vie maximale.",DE="When you Lunge at an enemy you now heal for 5% of your maximum health.",N="Sombre intention"}
DB[707623]={D="Tant que votre vie est inférieure à 75 %, vous soignez désormais 3 % de tous les dégâts que vous infligez.",DE="While below 75% health, you now heal for 3% of all damage you deal.",N="Lune de sang"}
DB[707624]={D="Augmente les dégâts physiques subis par les ennemis à moins de 5 mètres de vous de 3%.",DE="Increases the Physical damage taken by enemies within 5 yds of you by 3%.",N="Marque de sang"}
DB[707626]={D="Augmente l'efficacité du Pacte de Sang de 50%.",DE="Increases the effectiveness of Blood Pact by 50%.",N="Couvert de sang"}
DB[707627]={D="Augmente les dégâts et les dégâts critiques de Lichfrost de 20% contre les cibles malades.",DE="Increases the damage and critical damage of Lichfrost by 20% against diseased targets.",N="Fiélon"}
DB[707629]={D="Les attaques de blocage ont désormais 30 % de chances de vous accorder le Marteau des rois pendant 4 secondes.\nSi Hammer of Kings est déjà actif, vous augmentez la durée de 4 sec.\nMarteau des rois\nDevenez oint par la lumière, invoquant un marteau béni qui vous encercle, infligeant 5+1,8 points par niveau+AP*0,12+HolP*0,22 Dégâts du Feu sacré aux ennemis proches toutes les 3 s pendant 12 s.",DE="Blocking attacks now has a 30% chance to grant you Hammer of Kings for 4 sec.\nIf Hammer of Kings is already active, you increase the duration by 4 sec.\nHammer of Kings\nBecome anointed by the light, summoning a blessed hammer that encircles you dealing 5+1.8 Points Per Level+AP*0.12+HolP*0.22 Holyfire Damage to nearby enemies every 3 sec for 12 sec.",N="Égide d'éclat solaire"}
DB[707631]={D="Générer une charge de Sang de démon a désormais 5 % de chances de libérer votre Pestilence active à la moitié de son efficacité.",DE="Generating a stack of Demon's Blood now has a 5% chance to unleash your active Pestilence at half of their effectiveness.",N="Né des enfers"}
DB[707633]={D="Passif niveau 30\nAugmente votre puissance d'attaque de 20% de votre Force.",DE="Level 30 Passive\nIncreases your attack power by 20% of your Strength.",N="Combattant expérimenté"}
DB[707634]={D="Votre Gardien Spectral vous permet désormais d'invoquer 2 Gardiens Spectaux supplémentaires, mais leur durée est réduite de 8 sec.\nDe plus, augmente la quantité absorbée par le bouclier accordé par Spectral Warden de 100%.",DE="Your Spectral Warden now causes you to summon 2 additional Spectral Wardens, but their duration is reduced by 8 sec.\nIn addition, increases the amount absorbed by the shield granted by Spectral Warden by 100%.",N="Armée d'esprits"}
DB[707635]={D="Les coups critiques avec Astral Blade frappent désormais 2 fois supplémentaires, l'une pour 40 % des dégâts infligés et l'autre pour 20 % des dégâts infligés.",DE="Critical strikes with Astral Blade now strike 2 additional times, one for 40% of the damage dealt and the other for 20% of the damage dealt.",N="Garde de Maiev"}
DB[707636]={D="Réduit le temps de recharge de Lame astrale de 4 secondes.",DE="Reduces the cooldown of Astral Blade by 4 sec.",N="Finesse astrale"}
DB[707637]={D="Lancer Convergence stellaire réinitialise désormais le temps de recharge de Prière d’Élune.",DE="Casting Stellar Convergence now resets the cooldown of Prayer of Elune.",N="Dernière prière"}
DB[707638]={D="Passif niveau 20\nVous gagnez désormais passivement 1 charge de phase lunaire 1 seconde plus rapidement.",DE="Level 20 Passive\nYou now passively gain 1 stack of Lunar Phase 1 sec faster.",N="Esprit céleste"}
DB[707639]={D="Lancer Starfire Shot a désormais 20% de chances de vous accorder Cordon d'Elune pendant 5 secondes.\nCordon d'Elune\nHuntress Shot et Starcall appliquent une charge supplémentaire d'étoiles dispersées et la portée de votre attaque à distance est augmentée à 50 mètres.",DE="Casting Starfire Shot now has a 20% chance to grant you Drawstring of Elune for 5 sec.\nDrawstring of Elune\nHuntress Shot and Starcall apply an additional stack of Scattered Stars and your ranged ability attack range is increased to 50 yds.",N="Puissance du feu stellaire"}
DB[707640]={D="Blade of the Empire a désormais 30 % de chances de faire en sorte que votre prochaine attaque automatique frappe deux fois.",DE="Blade of the Empire now has a 30% chance to cause your next auto attack to hit twice.",N="Frappes de l'ombre"}
DB[707648]={D="Réduit le coût Rage de Tourmenteur et Damnation de 20%.",DE="Reduces the Rage cost of Tormentor and Damnation by 20%.",N="Poursuite ingénieuse"}
DB[707650]={D="Lorsque Mimic Ward est actif, vous gagnez désormais 15 % de hâte à distance en plus et votre récupération se transforme en Esprit Volley.\nChaque Esprit augmente désormais les dégâts du Esprit Volée de 3%.\nDe plus, les dégâts directs des capacités à distance infligés réduisent désormais le temps de recharge de Mimic Ward de 0,5 seconde.",DE="While Mimic Ward is active, you now gain 15% increased ranged haste and your Reclamation transforms into Spirit Volley.\nEach Spirit now increases the damage of Spirit Volley by 3%.\nIn addition, direct ranged abilty damage dealt now reduces the cooldown of Mimic Ward by 0.5 sec.",N="Don de Bwonsamdi"}
DB[707652]={D="Augmente le mana maximum, Rage, Énergie, Focalisation et Puissance runique des alliés à moins de 40 mètres de 3%.",DE="Increases the maximum mana, Rage, Energy, Focus, and Runic Power of allies within 40 yds by 3%.",N="Aura ionique"}
DB[707653]={D="Passer aux tatouages ​​runiques : Air dissipe désormais instantanément 1 effet de ralentissement de mouvement sur vous.",DE="Swapping to Runic Tattoos: Air now instantly dispels 1 movement slowing effect on you.",N="Parchemin du nomade"}
DB[707654]={D="Augmente la puissance des sorts de Frigid Blast de 50 %, mais le temps d'incantation est augmenté de 1 seconde.\nDe plus, Frigid Fusion accumule désormais 10 % de dégâts supplémentaires sur la cible.",DE="Increases the spell power scaling of Frigid Blast by 50%, but the cast time is increased by 1 sec.\nAdditionally, Frigid Fusion now accumulates 10% more damage on the target.",N="Éléments glaciaux"}
DB[707656]={D="Lancer Hâte réduit désormais également toujours le temps d'incantation de vos sorts de soins de 20 % supplémentaires.",DE="Casting Hasten now also always reduces the cast time of your healing spells by an additional 20%.",N="Créateur de réalités"}
DB[707657]={D="Les soins excessifs effectués par Corriger l'erreur appliquent désormais à l'allié un effet de soins sur la durée égal à 30 % des soins effectués en 5 s.",DE="Overhealing done by Correct the Mistake now applies a heal over time effect to the ally equal to 30% of the healing done over 5 sec.",N="Surcorrection"}
DB[707661]={D="Transforme votre arme de lancer en lancer de javelot et augmente les chances de coup critique du lancer de javelot de 5 %.\nLancer du javelot\nVisez et lancez un javelot sur un ennemi, infligeant 160 % des dégâts des armes à distance plus 241.\nÉchelle avec des modificateurs de dégâts pour lancer une arme et des lances. Utilisable en déplacement.",DE="Transforms your Throw Weapon into Javelin Toss and increases the critical strike chance of Javelin Toss by 5%.\nJavelin Toss\nTake aim and hurl a javelin at an enemy dealing 160% Ranged Weapon Damage plus 241.\nScales with damage modifiers to Throw Weapon and Spears. Usable while moving.",N="Conduite de Sen'jin"}
DB[707663]={D="Supprime le temps de recharge de Bénédiction, mais augmente son coût en Énergie de 10.",DE="Removes the cooldown from Benediction, but increases its Energy cost by 10.",N="Justicier de la Lumière"}
DB[707668]={D="Transforme la forme d'araignée en Seigneur des couvées, ce qui amène vos dépensiers de Marques de couvée à lancer des toiles sur la cible, s'y collant pendant 10 s.\nLa vitesse de déplacement de chaque cible palmée est ralentie de 25 %.\nFrapper de manière critique un ennemi palmé invoque 1 à 2 Spiderlings pour vous aider au combat pendant 8 s.",DE="Augments Spider Form into a Brood Lord, causing your Brood Mark spenders to launch webs at the target, sticking to them for 10 sec.\nEach webbed target has their movement speed slowed by 25%.\nCritically striking an enemy who is webbed summons 1 to 2 Spiderlings to aid you in combat for 8 sec.",N="Seigneur de couvée"}
DB[707707]={D="Les coups critiques à dégâts directs génèrent désormais un fragment d’âme supplémentaire.",DE="Direct damage critical strikes now generate an additional Soul Fragment.",N="Sillage rouge"}
DB[707716]={D="Les dégâts infligés par Marteau de la loi réduisent désormais les dégâts infligés par les ennemis affectés de 10 % pendant 8 s.",DE="Damage dealt by Hammer of the Law now reduces the damage dealt by affected enemies by 10% for 8 sec.",N="Silence dans la cour"}
DB[707717]={D="Passif niveau 50\nGagner en puissance écrasante garantit désormais également à votre prochaine marque runique de frapper de manière critique.",DE="Level 50 Passive\nGaining Power Overwhelming now also guarantees your next Runic Brand to critically strike.",N="Marqué au fer"}
DB[707719]={D="Le vent est toujours dans votre dos, vous poussant à vous déplacer plus rapidement, augmentant ainsi votre vitesse de déplacement et celle de votre monture de 15 %.",DE="The wind is always at your back, pushing you to move faster, increasing your movement speed and mounted movement speed by 15%.",N="Coursevent"}
aura(707721, "Reduces the duration of poison effects on you by 40%.", "Réduit la durée des effets du poison sur vous de 40 %.")
DB[707726]={D="Augmente les soins critiques de la prière de Shadra de 25%.",DE="Increases the critical healing of Shadra's Prayer by 25%.",N="Venins apaisants"}
DB[707744]={D="Les coups critiques directs derrière votre cible augmentent votre hâte de 15 % pendant 5 s ou pour vos 2 prochaines attaques.",DE="Direct critical strikes while behind your target increase your haste by 15% for 5 sec, or for your next 2 attacks.",N="Bandit de grand chemin"}
DB[707745]={D="Augmente votre hâte en mêlée de 6% et réduit la durée des effets de racine contre vous de 30%.",DE="Increases your melee haste by 6% and reduces the duration of root effects against you by 30%.",N="Poursuite infernale"}
DB[707746]={D="Augmente votre vitesse de déplacement de 15 % et réduit le coût en mana de vos tatouages ​​runiques de 50 %.",DE="Increases your movement speed by 15% and reduces the mana cost of your Runic Tattoos by 50%.",N="Harmonisateur rapide"}
DB[707747]={D="Supprime le temps de recharge de Emprise de Zek'voz, mais augmente son coût en mana de 25 %.",DE="Removes the cooldown of Grasp of Zek'voz, but increases its mana cost by 25%.",N="Dédain"}
DB[707748]={D="Votre Regard de C'Thun frappe désormais 2 ennemis proches supplémentaires.",DE="Your Gaze of C'Thun now strikes 2 additional nearby enemies.",N="Fendoir abyssal"}
DB[707749]={D="Vos attaques automatiques infligent désormais 20 % supplémentaires des dégâts infligés sous forme de dégâts Ombre.",DE="Your auto attacks now deal an additional 20% of the damage dealt as Shadow damage.",N="Tranchant forgé dans le Vide"}
DB[707751]={D="Augmente les chances de coup critique et les dégâts critiques de Starfire Shot de 10 % contre les cibles en feu.",DE="Increases the critical strike chance and critical damage of Starfire Shot by 10% against Burning targets.",N="Entraînement de Tyrande"}
DB[707753]={D="Au-dessus de 40 Insanity, vos chances de déclencher Dark Revelation sont désormais augmentées de 10 %.",DE="While above 40 Insanity, your chance to trigger Dark Revelation is now increased by 10%.",N="Visions horrifiques"}
aura(707754, "Increases your movement speed and reduces the duration of movement slowing effects on you by 10%.", "Augmente votre vitesse de déplacement et réduit la durée des effets de ralentissement des mouvements sur vous de 10 %.")
DB[707760]={D="Augmente les chances de coup critique de Brutal Swing et Smash de 10 %.",DE="Increases the critical strike chance of Brutal Swing and Smash by 10%.",N="Combattant sanglant"}
DB[707761]={D="Augmente les dégâts de Smash de 30% et votre expertise de 10.",DE="Increases the damage of Smash by 30% and your expertise by 10.",N="Puissance pure"}
DB[707762]={D="Réduit le temps de recharge de Crush de 5 secondes.",DE="Reduces the cooldown of Crush by 5 sec.",N="Coups puissants"}
DB[707765]={D="Augmente les dégâts de Throw Weapon, Gutspiller et Guts Spilled de 20%.",DE="Increases the damage of Throw Weapon, Gutspiller, and Guts Spilled by 20%.",N="Atroce"}
DB[707766]={D="Augmente les dégâts de Keg Smash de 20% et sa portée de 6 mètres.",DE="Increases the damage of Keg Smash by 20% and its range by 6 yds.",N="Virée à la taverne"}
DB[707767]={D="Augmente l'efficacité de vos dévotions de 20%.",DE="Increases the effectiveness of your Devotions by 20%.",N="Dévot"}
DB[707770]={D="Augmente vos dégâts Sacré et vos soins prodigués de 8%.",DE="Increases your Holy damage and healing done by 8%.",N="Vision divine"}
DB[707771]={D="Réduit le temps d'incantation d'Illumination de 0,5 seconde.",DE="Reduces the cast time of Ilumination by 0.5 sec.",N="Angélique"}
DB[707772]={D="Augmente votre Force et votre mana maximum de 10% et votre expertise de 10.",DE="Increases your Strength and maximum mana by 10% and your expertise by 10.",N="Impartial"}
DB[707773]={D="Votre Exécution Glorieuse ignore désormais 20% de l'armure de la cible pendant que Vœu du Valkyr est actif.",DE="Your Glorious Execution now ignores 20% of the target's armor while Vow of the Valkyr is active.",N="Vindicateur"}
DB[707777]={D="Réduit le coût en Énergie du Combat Ancestral de 30 et lui permet de se déclencher 10 fois supplémentaires.",DE="Reduces the Energy cost of Ancestral Combat by 30 and allows it to trigger 10 additional times.",N="Combat ancestral amélioré"}
DB[707778]={D="Chaque charge de niveau de remplissage augmente désormais également les dégâts Givre infligés de 4 %.",DE="Each Fill Level stack now also increases Frost damage dealt by 4%.",N="Bulles glacées"}
DB[707779]={D="Augmente les chances de coup critique des lances et de la hache berserker de 15 % contre les cibles qui saignent.",DE="Increases the critical strike chance of Spears and Berserker Axe by 15% against bleeding targets.",N="Sauvage écumant"}
DB[707781]={D="Augmente tous les attributs principaux de 8%.",DE="Increases all primary attributes by 8%.",N="Commandant de l'empire"}
DB[707783]={D="Réduit de 70 % le rejet des sorts subis par les attaques dommageables et augmente le mana généré par Sanity Tap de 10 %.",DE="Reduces spell pushback suffered from damaging attacks by 70% and increases mana generated by Sanity Tap by 10%.",N="Moment de lucidité"}
DB[707784]={D="Augmente vos chances de toucher de 6 % et réduit de 30 % la menace générée par les sorts de dégâts Ombre.",DE="Increases your chance to hit by 6% and reduces threat generated by Shadow damage spells by 30%.",N="Nature rusée"}
DB[707785]={D="Vos attaques automatiques infligent désormais 30 % supplémentaires des dégâts infligés sous forme de dégâts Ombre.",DE="Your auto attacks now deal an additional 30% of the damage dealt as Shadow damage.",N="Tranchant forgé dans le Vide"}
DB[707786]={D="Les soins efficaces effectués par Ember Touch soignent désormais jusqu'à 3 des alliés ayant le moins de vie près de votre cible pour 30 % supplémentaires du montant soigné.",DE="Effective healing done by Ember Touch now heals up to 3 of the lowest health allies near your target for an additional 30% of the amount healed.",N="Toucher délicat"}
DB[707787]={D="Augmente le taux de tick de Blaze et Ignite de 20%.",DE="Increases the tick rate of Blaze and Ignite by 20%.",N="Explosif"}
DB[707789]={D="Augmente vos Intelligence et vos chances de coup critique de 6%.",DE="Increases your Intellect and critical strike chance by 6%.",N="Pression critique"}
DB[707790]={D="Augmente les dégâts de la Gueule du Destructeur de 40%.",DE="Increases the damage of Destroyer's Maw by 40%.",N="Sceptre de l'Aspect fou"}
DB[707792]={D="Augmente les chances de coup critique de Call Lightning et Arm of Thorim de 30% contre les cibles affectées par votre Volt.",DE="Increases the critical strike chance of Call Lightning and Arm of Thorim by 30% against targets affected by your Volt.",N="Fulmination"}
DB[707793]={D="Augmente la puissance des sorts de Choc, Appel de la foudre et Bras de Thorim de 30 %.",DE="Increases the spell power scaling of Shock, Call Lightning, and Arm of Thorim by 30%.",N="Invocation des tempêtes"}
DB[707794]={D="Augmente les chances de coup critique de Choc, Conjuration de Tempête et Œil de la tempête de 8 %.",DE="Increases the critical strike chance of Shock, Conjure Storm, and Eye of the Storm by 8%.",N="Foudre titanesque"}
DB[707795]={D="Réduit le temps d'incantation de votre Colère torrentielle de 0,4 seconde et augmente vos chances de toucher de 4%.",DE="Reduces the cast time of your Torrential Wrath by 0.4 sec and increases your hit chance by 4%.",N="Disciple de Thorim"}
DB[707796]={D="Augmente les chances de coup critique de Noyade de 50%.",DE="Increases the critical strike chance of Drown by 50%.",N="Ressac"}
DB[707797]={D="Augmente les chances de coup critique d'Électrocution de 60 % contre les ennemis ayant moins de 20 % de vie.",DE="Increases the critical strike chance of Electrocute by 60% against enemies below 20% health.",N="Courant mortel"}
DB[707798]={D="Réduit le temps d'incantation de votre Colère torrentielle de 0,6 seconde et augmente vos chances de toucher de 6%.",DE="Reduces the cast time of your Torrential Wrath by 0.6 sec and increases your hit chance by 6%.",N="Disciple de Thorim"}
DB[707799]={D="Augmente les dégâts infligés par les sorts de votre Élémentaire d'Air de 20% et vos dégâts de Nature infligés de 4%.",DE="Increases the damage dealt by your Air Elemental's spells by 20% and your Nature damage dealt by 4%.",N="Alimenter les éléments"}
DB[707800]={D="Augmente la durée de Revigoration de 10 secondes.",DE="Increases the duration of Invigoration by 10 sec.",N="Revigoration éternelle"}
DB[707801]={D="Augmente la durée de votre courant ascendant de 6 secondes et augmente son taux de tick de 30%.",DE="Increases the duration of your Updraft by 6 sec and increases its tick rate by 30%.",N="Esquisse rapide"}
DB[707802]={D="Augmente les dégâts de Deathwind, Murder et Soul Strike de 30%.",DE="Increases the damage of Deathwind, Murder, and Soul Strike by 30%.",N="Appel du spectre"}
DB[707803]={D="Augmente la hâte de vos sorts de 8%.",DE="Increases your spell haste by 8%.",N="Attaques chronométrées"}
DB[707807]={D="Augmente vos soins effectués et reçus de 12%.",DE="Increases your healing done and received by 12%.",N="Appel de la nature"}
DB[707808]={D="Augmente vos chances de parade et d'esquive de 6 % et la contribution d'armure de vos objets en mailles et en plaques de 50 %.",DE="Increases your parry and dodge chance by 6% and your Armor contribution from mail and plate by 50%.",N="Forme inflexible"}
DB[707809]={D="Augmente votre Armure de 400% de votre Intelligence.",DE="Increases your Armor by 400% of your Intellect.",N="Peau de pierre"}
DB[707810]={D="Augmente la durée du tremblement de terre de 3 secondes et augmente les dégâts infligés de 25%.",DE="Increases the duration Earthquake by 3 sec and increases its damage dealt by 25%.",N="Puissance tectonique"}
DB[707811]={D="Augmente les chances de coup critique de Totemic Smash de 20%.",DE="Increases the critical strike chance of Totemic Smash by 20%.",N="Pulvériser"}
DB[707812]={D="Augmente votre Force de 10% et votre expertise de 8.",DE="Increases your Strength by 10% and your expertise by 8.",N="Griffes de raptor"}
DB[707813]={D="Augmente votre Force de 8% et votre expertise de 4.",DE="Increases your Strength by 8% and expertise by 4.",N="Vaillant"}
DB[707814]={D="Augmente votre contribution Armure de votre bouclier de 40%.",DE="Increases your Armor contribution from your shield by 40%.",N="Mur protecteur"}
DB[707815]={D="Augmente la valeur de blocage fournie par Raise Shield de 50 % et vos chances de blocage de 2 %.",DE="Increases the block value provided by Raise Shield by 50% and your block chance by 2%.",N="Conviction du chevalier"}
DB[707816]={D="Augmente votre Endurance de 10%.",DE="Increases your Stamina by 10%.",N="Gardien de fer"}
DB[707817]={D="Augmente votre valeur de bloc de 20% et votre expertise de 8.",DE="Increases your block value by 20% and your expertise by 8.",N="Inébranlable"}
DB[707818]={D="Nécessite des haches à une main\nLorsqu'une hache est équipée, vos chances de coup critique sont augmentées de 4 % et vos dégâts critiques de 10 %.",DE="Requires One-Handed Axes\nWhile an axe is equipped, your critical strike chance is increased by 4% and critical damage increased by 10%.",N="Maniement de la hache"}
