DB[578344]={D="Donne à un allié le pouvoir du vaudou, réduisant ainsi son coût en ressources de 5 %. Dure 30 minutes.",DE="Empowers an ally with da voodoo, reducing their resource costs by 5%. Lasts 30 min.",N="Wuju ingénieux"}
