DB[2100095]={D="Réduit au silence les ennemis proches, les empêchant de lancer des sorts pendant 2 sec.",DE="Silences nearby enemies, preventing them from casting spells for 2 sec.",N="Cri strident"}
DB[2100138]={D="Inflige 800 à 1050 points de dégâts de Feu aux ennemis se trouvant dans un cône devant le lanceur et les brûle pour 80 à 105 points de dégâts de Feu supplémentaires chaque seconde pendant 10 s. Empilable jusqu'à 3 fois.",DE="Inflicts 800 to 1050 Fire damage to enemies in a cone infront of the caster and burns them for an additional 80 to 105 Fire damage every second for 10 sec. Stacking up to 3 times.",N="Volée de boules de feu"}
DB[2100140]={D="Les ennemis proches sont gelés dans la glace, les rendant incapables d'agir.",DE="Causes nearby enemies to become frozen in ice, making them unable to act.",N="Congélation"}
DB[2100141]={D="Réduit la vitesse d'attaque, d'incantation et de déplacement des ennemis proches de 20 % pendant 10 secondes.",DE="Reduces attack, casting and movement speed of earby enemies by 20% for 10 sec.",N="Lenteur de masse"}
DB[2100151]={D="Prononce un mot des ténèbres, infligeant 667 Ombre de dégâts à un ennemi toutes les 3 s. pendant 15 secondes.",DE="Utters a word of darkness, inflicting 667 Shadow damage to an enemy every 3 sec. for 15 sec.",N="Mot de l'ombre : Douleur"}
