DB[2100215]={D="Sacrifie la cible, l'étourdit et lui fait subir 17 % de dégâts de santé maximum par seconde.",DE="Sacrifices the target, stunning it and causes it to suffer 17% maximum health damage per second.",N="Sacrifice"}
