DB[2100253]={D="Endort un ennemi, le rendant incapable d'agir pendant 5 secondes maximum. Tout dommage causé réveillera la cible.",DE="Puts an enemy to sleep, making it unable to act for up to 5 sec. Any damage caused will awaken the target.",N="Sommeil"}
