DB[2100374]={D="Corrompt la cible, lui infligeant 71 à 84 Ombre de dégâts toutes les 3 secondes pendant 24 s.",DE="Corrupts the target, causing 71 to 84 Shadow damage every 3 seconds for 24 sec.",N="Corruption"}
